package com.example.samlsp.saml;

import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.saml.common.SAMLVersion;
import org.opensaml.saml.common.xml.SAMLConstants;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.saml.saml2.core.impl.*;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.signature.support.SignatureConstants;
import org.springframework.stereotype.Service;

import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.UUID;

@Service
public class SamlAuthnRequestService {

    private final SamlProperties props;
    private final SamlEncoding encoding;
    private final Credential signingCredential;

    public SamlAuthnRequestService(SamlProperties props, SamlEncoding encoding) {
        this.props = props;
        this.encoding = encoding;
        this.signingCredential = SamlSigning.loadSigningCredential(props);
    }

    public String buildRedirectUrl(String relayState) {
        AuthnRequest req = buildAuthnRequest();
        SamlSigning.sign(req, signingCredential);
        String xml = SamlXml.toXml(req);
        String samlRequest = encoding.deflateAndBase64Encode(xml.getBytes(StandardCharsets.UTF_8));

        StringBuilder sb = new StringBuilder();
        sb.append(props.getIdpSsoUrl());
        sb.append(props.getIdpSsoUrl().contains("?") ? "&" : "?");
        sb.append("SAMLRequest=").append(urlEncode(samlRequest));
        if (relayState != null && !relayState.isBlank()) {
            sb.append("&RelayState=").append(urlEncode(relayState));
        }
        return sb.toString();
    }

    private AuthnRequest buildAuthnRequest() {
        AuthnRequestBuilder builder = (AuthnRequestBuilder) XMLObjectProviderRegistrySupport.getBuilderFactory()
            .getBuilder(AuthnRequest.DEFAULT_ELEMENT_NAME);
        AuthnRequest req = builder.buildObject();

        req.setID("_" + UUID.randomUUID());
        req.setIssueInstant(Instant.now());
        req.setVersion(SAMLVersion.VERSION_20);
        req.setDestination(props.getIdpSsoUrl());
        req.setProtocolBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        req.setAssertionConsumerServiceURL(props.getAcsUrl());

        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(props.getEntityId());
        req.setIssuer(issuer);

        NameIDPolicy nameIDPolicy = new NameIDPolicyBuilder().buildObject();
        nameIDPolicy.setAllowCreate(true);
        nameIDPolicy.setFormat(NameIDType.PERSISTENT);
        req.setNameIDPolicy(nameIDPolicy);

        RequestedAuthnContext rac = new RequestedAuthnContextBuilder().buildObject();
        rac.setComparison(AuthnContextComparisonTypeEnumeration.EXACT);
        AuthnContextClassRef classRef = new AuthnContextClassRefBuilder().buildObject();
        classRef.setURI(AuthnContext.PPT_AUTHN_CTX);
        rac.getAuthnContextClassRefs().add(classRef);
        req.setRequestedAuthnContext(rac);

        return req;
    }

    private static String urlEncode(String s) {
        try {
            return java.net.URLEncoder.encode(s, java.nio.charset.StandardCharsets.UTF_8.name());
        } catch (Exception e) {
            throw new IllegalStateException(e);
        }
    }
}

package com.example.samlsp.saml;

import org.opensaml.core.xml.XMLObject;
import org.opensaml.saml.common.SignableSAMLObject;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureException;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.opensaml.security.credential.Credential;
import org.opensaml.security.credential.CredentialSupport;
import org.opensaml.security.x509.BasicX509Credential;
import org.opensaml.xmlsec.keyinfo.KeyInfoSupport;
import org.opensaml.xmlsec.signature.KeyInfo;
import org.springframework.stereotype.Service;

import java.security.cert.X509Certificate;
import java.time.Instant;
import java.util.*;

@Service
public class SamlResponseValidator {

    private final SamlProperties props;

    public SamlResponseValidator(SamlProperties props) {
        this.props = props;
    }

    public ValidationResult validateAndExtract(String base64Response) {
        String xml = new String(java.util.Base64.getDecoder().decode(base64Response), java.nio.charset.StandardCharsets.UTF_8);
        XMLObject obj = SamlXml.fromXml(xml);
        if (!(obj instanceof Response response)) {
            throw new IllegalArgumentException("Not a SAML Response");
        }

        if (props.isWantResponseSigned()) {
            validateSignature(response);
        }

        if (response.getStatus() == null || response.getStatus().getStatusCode() == null ||
            !StatusCode.SUCCESS.equals(response.getStatus().getStatusCode().getValue())) {
            throw new IllegalStateException("SAML Response status not success");
        }

        Assertion assertion = null;
        if (response.getAssertions() != null && !response.getAssertions().isEmpty()) {
            assertion = response.getAssertions().get(0);
        } else if (response.getEncryptedAssertions() != null && !response.getEncryptedAssertions().isEmpty()) {
            throw new IllegalStateException("EncryptedAssertions not supported in this minimal sample");
        } else {
            throw new IllegalStateException("No assertion in response");
        }

        if (props.isWantAssertionsSigned()) {
            validateSignature(assertion);
        }

        validateConditions(assertion);

        String nameId = null;
        if (assertion.getSubject() != null && assertion.getSubject().getNameID() != null) {
            nameId = assertion.getSubject().getNameID().getValue();
        }

        Map<String, List<String>> attrs = new LinkedHashMap<>();
        if (assertion.getAttributeStatements() != null) {
            for (AttributeStatement st : assertion.getAttributeStatements()) {
                for (Attribute a : st.getAttributes()) {
                    List<String> values = new ArrayList<>();
                    for (XMLObject v : a.getAttributeValues()) {
                        String text = v.getDOM() != null ? v.getDOM().getTextContent() : null;
                        if (text != null) values.add(text);
                    }
                    attrs.put(a.getName(), values);
                }
            }
        }

        String sessionIndex = null;
        if (assertion.getAuthnStatements() != null && !assertion.getAuthnStatements().isEmpty()) {
            sessionIndex = assertion.getAuthnStatements().get(0).getSessionIndex();
        }

        return new ValidationResult(nameId, sessionIndex, attrs);
    }

    private void validateConditions(Assertion assertion) {
        Conditions c = assertion.getConditions();
        if (c == null) return;

        Instant now = Instant.now();

        if (c.getNotBefore() != null && now.isBefore(c.getNotBefore().minusSeconds(60))) {
            throw new IllegalStateException("Assertion not yet valid");
        }
        if (c.getNotOnOrAfter() != null && !now.isBefore(c.getNotOnOrAfter().plusSeconds(60))) {
            throw new IllegalStateException("Assertion expired");
        }

        if (c.getAudienceRestrictions() != null && !c.getAudienceRestrictions().isEmpty()) {
            boolean ok = false;
            for (AudienceRestriction ar : c.getAudienceRestrictions()) {
                for (Audience aud : ar.getAudiences()) {
                    if (props.getEntityId().equals(aud.getURI())) {
                        ok = true;
                        break;
                    }
                }
            }
            if (!ok) throw new IllegalStateException("Audience restriction failed");
        }
    }

    private void validateSignature(SignableSAMLObject obj) {
        Signature sig = obj.getSignature();
        if (sig == null) throw new IllegalStateException("Missing signature");
        Credential cred = extractCredentialFromKeyInfo(sig.getKeyInfo());
        try {
            SignatureValidator.validate(sig, cred);
        } catch (SignatureException e) {
            throw new IllegalStateException("Signature invalid", e);
        }
    }

    private Credential extractCredentialFromKeyInfo(KeyInfo keyInfo) {
        if (keyInfo == null) throw new IllegalStateException("Missing KeyInfo");
        List<X509Certificate> certs = KeyInfoSupport.getCertificates(keyInfo);
        if (certs == null || certs.isEmpty()) throw new IllegalStateException("No certificate in KeyInfo");
        X509Certificate cert = certs.get(0);
        BasicX509Credential cred = CredentialSupport.getSimpleCredential(cert, null);
        return cred;
    }

    public record ValidationResult(String nameId, String sessionIndex, Map<String, List<String>> attributes) {}
}

package com.example.samlsp.web;

import com.example.samlsp.saml.SamlAuthnRequestService;
import com.example.samlsp.saml.SamlProperties;
import com.example.samlsp.saml.SamlResponseValidator;
import com.example.samlsp.saml.SamlSigning;
import org.opensaml.security.credential.Credential;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import java.security.KeyStore;
import java.security.cert.X509Certificate;
import java.util.UUID;

@RestController
@RequestMapping("/saml")
public class SamlController {

    private final SamlProperties props;
    private final SamlAuthnRequestService authnRequestService;
    private final SamlResponseValidator responseValidator;

    public SamlController(SamlProperties props, SamlAuthnRequestService authnRequestService, SamlResponseValidator responseValidator) {
        this.props = props;
        this.authnRequestService = authnRequestService;
        this.responseValidator = responseValidator;
    }

    @GetMapping("/login")
    public ResponseEntity<Void> login(@RequestParam(value = "relayState", required = false) String relayState,
                                      HttpServletRequest request) {
        if (relayState == null || relayState.isBlank()) {
            relayState = request.getContextPath() + "/";
        }
        String url = authnRequestService.buildRedirectUrl(relayState);
        return ResponseEntity.status(302).header("Location", url).build();
    }

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public ResponseEntity<String> acs(@RequestParam("SAMLResponse") String samlResponse,
                                      @RequestParam(value = "RelayState", required = false) String relayState,
                                      HttpServletRequest request) {
        SamlResponseValidator.ValidationResult result = responseValidator.validateAndExtract(samlResponse);

        HttpSession session = request.getSession(true);
        session.setAttribute("saml.nameId", result.nameId());
        session.setAttribute("saml.sessionIndex", result.sessionIndex());
        session.setAttribute("saml.attributes", result.attributes());

        String target = (relayState == null || relayState.isBlank()) ? "/" : relayState;
        return ResponseEntity.status(302).header("Location", target).body("Redirecting");
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public ResponseEntity<String> metadata() {
        String xml = buildSpMetadataXml();
        return ResponseEntity.ok(xml);
    }

    @GetMapping("/logout")
    public ResponseEntity<String> logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) session.invalidate();
        return ResponseEntity.ok("Logged out");
    }

    @PostMapping(value = "/slo", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public ResponseEntity<String> slo(@RequestParam(value = "SAMLRequest", required = false) String samlRequest,
                                      @RequestParam(value = "SAMLResponse", required = false) String samlResponse) {
        return ResponseEntity.ok("SLO endpoint placeholder");
    }

    private String buildSpMetadataXml() {
        Credential cred = SamlSigning.loadSigningCredential(props);
        X509Certificate cert = (X509Certificate) ((org.opensaml.security.x509.X509Credential) cred).getEntityCertificate();
        String certB64 = SamlSigning.certificateToBase64(cert);

        String entityId = escape(props.getEntityId());
        String acs = escape(props.getAcsUrl());

        String id = "_" + UUID.randomUUID();

        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n" +
            "<md:EntityDescriptor xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\" entityID=\"" + entityId + "\" ID=\"" + id + "\">\n" +
            "  <md:SPSSODescriptor AuthnRequestsSigned=\"true\" WantAssertionsSigned=\"" + props.isWantAssertionsSigned() + "\" protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\">\n" +
            "    <md:KeyDescriptor use=\"signing\">\n" +
            "      <ds:KeyInfo xmlns:ds=\"http://www.w3.org/2000/09/xmldsig#\">\n" +
            "        <ds:X509Data>\n" +
            "          <ds:X509Certificate>" + certB64 + "</ds:X509Certificate>\n" +
            "        </ds:X509Data>\n" +
            "      </ds:KeyInfo>\n" +
            "    </md:KeyDescriptor>\n" +
            "    <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>\n" +
            "    <md:AssertionConsumerService index=\"0\" isDefault=\"true\" Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" Location=\"" + acs + "\"/>\n" +
            "  </md:SPSSODescriptor>\n" +
            "</md:EntityDescriptor>\n";
    }

    private static String escape(String s) {
        if (s == null) return "";
        return s.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace("\"", "&quot;").replace("'", "&apos;");
    }
}

package com.example.samlsp.web;

import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import jakarta.servlet.http.HttpServletRequest;
import java.util.Map;

@RestController
public class AppController {

    @GetMapping("/")
    public Map<String, Object> home(HttpServletRequest request) {
        var session = request.getSession(false);
        Object nameId = session != null ? session.getAttribute("saml.nameId") : null;
        Object attrs = session != null ? session.getAttribute("saml.attributes") : null;
        Object sessionIndex = session != null ? session.getAttribute("saml.sessionIndex") : null;
        return Map.of(
            "authenticated", nameId != null,
            "nameId", nameId,
            "sessionIndex", sessionIndex,
            "attributes", attrs
        );
    }
}

package com.example.samlsp;

import org.springframework.boot.web.servlet.ServletContextInitializer;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class WebConfig {
    @Bean
    public ServletContextInitializer servletContextInitializer() {
        return servletContext -> servletContext.getSessionCookieConfig().setHttpOnly(true);
    }
}

